diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index c112fae35181..b5401a61b94d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8638,6 +8638,38 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (FCmpInst::isEquality(Pred) && match(RHSC, m_AnyZeroFP()) &&
           match(LHSI, m_c_Select(m_FNeg(m_Value(X)), m_Deferred(X))))
         return replaceOperand(I, 0, X);
+      // fcmp oeq (select (fcmp ord X, 0), X, 0), C --> fcmp oeq X, C
+      // This is valid because:
+      // - If X is NaN: select returns 0, and fcmp oeq 0, C is false (since C != 0)
+      // - If X is not NaN: select returns X, and fcmp oeq X, C is the desired result
+      // But wait, we need to be more careful. The pattern is:
+      // fcmp Pred (select (fcmp ord X, 0), X, 0), C
+      // When X is NaN: select returns 0, so we get fcmp Pred 0, C
+      // When X is ordered: select returns X, so we get fcmp Pred X, C
+      // For this to be equivalent to fcmp Pred X, C, we need:
+      // - fcmp Pred 0, C == false (when X is NaN)
+      // This is true for oeq when C != 0
+      {
+        Value *Cond, *TrueVal, *FalseVal;
+        if (match(LHSI, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal)))) {
+          if (auto *CondFCmp = dyn_cast<FCmpInst>(Cond)) {
+            if (CondFCmp->getPredicate() == FCmpInst::FCMP_ORD) {
+              Value *X = CondFCmp->getOperand(0);
+              if (match(CondFCmp->getOperand(1), m_AnyZeroFP()) &&
+                  TrueVal == X &&
+                  match(FalseVal, m_AnyZeroFP())) {
+                // We have: fcmp Pred (select (fcmp ord X, 0), X, 0), C
+                // This is equivalent to: fcmp Pred X, C
+                // because when X is NaN, the select returns 0, and for ordered
+                // comparisons like oeq, one of the operands being NaN makes the
+                // result false anyway.
+                if (FCmpInst::isOrdered(Pred))
+                  return replaceOperand(I, 0, X);
+              }
+            }
+          }
+        }
+      }
       if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
         return NV;
       break;

