                // because when X is NaN, the select returns 0, and for ordered
                // comparisons like oeq, one of the operands being NaN makes the
                // result false anyway.
                if (FCmpInst::isOrdered(Pred))
                  return replaceOperand(I, 0, X);
              }
            }
          }
        }
      }
      if (Instruction *NV = FoldOpIntoSelect(I, cast<SelectInst>(LHSI)))
        return NV;
      break;
